 OpenClaw 对话状态管理：从 Session 存储到 Context Engine 的源码级拆解 # 基于 OpenClaw v2026.4.21 源码深度分析 作者：小伟 | 2026-04-30
导读 # 一个 LLM Agent 能&quot;记住&quot;什么、如何管理对话上下文、如何在有限的 context window 中塞入最有价值的信息，这些是 Agent 系统的核心挑战。OpenClaw 的对话状态管理不是简单的&quot;把历史消息传给模型&quot;，而是一个分层架构：从持久化存储 → Session 生命周期 → Session Manager → Context Engine → Compaction → Transcript Repair，每一层各司其职。
本文将从源码级别完整拆解这一架构。
1. 总览：对话状态管理架构 # ┌──────────────────────────────────────────────────────────────────────────┐ │ OpenClaw 对话状态管理体系 │ │ │ │ ┌────────────────────────────────────────────────────────────────────┐ │ │ │ 存储层：持久化 │ │ │ │ Session Store (sessions.json) + JSONL Transcript (session.jsonl) │ │ │ │ + Session Store Cache + Session Write Lock │ │ │ └────────────────────────────────┬───────────────────────────────────┘ │ │ │ │ │ ┌────────────────────────────────▼───────────────────────────────────┐ │ │ │ 会话层：Session 生命周期 │ │ │ │ Session 创建 / 路由 / 分组 / 维护（prune/rotate/maintenance） │ │ │ └────────────────────────────────┬───────────────────────────────────┘ │ │ │ │ │ ┌────────────────────────────────▼───────────────────────────────────┐ │ │ │ 引擎层：Session Manager + Context Engine │ │ │ │ SessionManager (pi-coding-agent) + Context Engine (assemble/ingest)│ │ │ │ + Context Window Guard + Token Estimation │ │ │ └────────────────────────────────┬───────────────────────────────────┘ │ │ │ │ │ ┌────────────────────────────────▼───────────────────────────────────┐ │ │ │ 维护层：Compaction + Maintenance │ │ │ │ Context Engine Maintenance + Compaction + Session Truncation │ │ │ │ + Transcript Rewrite + Tool Result Truncation │ │ │ └────────────────────────────────┬───────────────────────────────────┘ │ │ │ │ │ ┌────────────────────────────────▼───────────────────────────────────┐ │ │ │ 安全层：Repair + Guard │ │ │ │ Session File Repair + Tool Result Context Guard │ │ │ │ + Tool Use/Result Pairing Sanitize + Thinking Block Repair │ │ │ └────────────────────────────────────────────────────────────────────┘ │ │ │ └──────────────────────────────────────────────────────────────────────────┘ 2. 存储层：Session Store + JSONL Transcript # 2.1 双存储结构 # OpenClaw 使用两种文件格式来管理对话状态：
文件 路径 格式 用途 sessions.json ~/.openclaw/agents/&lt;agentId&gt;/sessions/sessions.json JSON Session 元数据索引（轻量） &lt;sessionId&gt;.jsonl ~/.openclaw/agents/&lt;agentId&gt;/sessions/&lt;sessionId&gt;.jsonl JSONL 完整对话记录（逐行 JSON） 源码：paths.ts / store.ts
2.2 Session Store 加载 # 源码：store-load.ts
// src/config/sessions/store-load.ts // 从文件系统加载 sessions.json async function loadSessionStore(storePath, options) { // 1. 优先从缓存读取 if (isSessionStoreCacheEnabled()) { const cached = readSessionStoreCache(storePath); if (cached) return cached; } // 2. 从磁盘读取 const content = await fs.readFile(storePath, &#34;utf-8&#34;); const store = JSON.parse(content); // 3. 清理过期条目 pruneStaleEntries(store); // 4. 限制最大条目数 capEntryCount(store, config.maxEntries); // 5. 写入缓存 writeSessionStoreCache(storePath, store); return store; } 2.3 Session 维护策略 # 源码：store-maintenance.ts
// src/config/sessions/store-maintenance.ts // 默认维护策略 const DEFAULT_SESSION_PRUNE_AFTER_MS = 720 * 60 * 60 * 1000; // 30 天 const DEFAULT_SESSION_MAX_ENTRIES = 500; // 最大 500 条 const DEFAULT_SESSION_ROTATE_BYTES = 10485760; // 10 MB 轮转 const DEFAULT_SESSION_MAINTENANCE_MODE = &#34;enforce&#34;; // 强制模式 const DEFAULT_SESSION_DISK_BUDGET_HIGH_WATER_RATIO = 0.8; // 高水位 80% function resolveMaintenanceConfigFromInput(maintenance) { return { mode: maintenance?.mode ?? DEFAULT_SESSION_MAINTENANCE_MODE, pruneAfterMs: resolvePruneAfterMs(maintenance), maxEntries: maintenance?.maxEntries ?? DEFAULT_SESSION_MAX_ENTRIES, rotateBytes: resolveRotateBytes(maintenance), maxDiskBytes: resolveMaxDiskBytes(maintenance), highWaterBytes: resolveHighWaterBytes(maintenance, maxDiskBytes) }; } // 清理过期条目 function pruneStaleEntries(store, overrideMaxAgeMs) { const cutoffMs = Date.now() - maxAgeMs; for (const [key, entry] of Object.entries(store)) { if (entry?.updatedAt != null &amp;&amp; entry.updatedAt &lt; cutoffMs) { delete store[key]; // 直接删除 } } } 2.4 High-Water 磁盘预算策略 # // High-Water 策略：写入超过 cap 时批量清理，而非每次都触发完整清理 function resolveHighWaterBytes(maintenance, maxDiskBytes) { if (maxDiskBytes == null) return null; return Math.floor(maxDiskBytes * 0.8); // 80% 水位线 } 2.5 Session 文件轮转 # 源码：store-load.ts
// src/config/sessions/store-load.ts // 当 session 文件超过 rotateBytes 时自动轮转 function rotateSessionFile(sessionFile, rotateBytes) { const stat = fs.statSync(sessionFile); if (stat.size &gt; rotateBytes) { // 归档旧文件 const archivePath = `${sessionFile}.${Date.now()}.archive`; fs.renameSync(sessionFile, archivePath); } } 2.6 Session Store 缓存 # 源码：store-cache.ts
// Session Store 缓存机制 function isSessionStoreCacheEnabled() { ... } function readSessionStoreCache(storePath) { ... } function writeSessionStoreCache(storePath, store) { ... } function setSerializedSessionStore(key, value) { ... } function getSerializedSessionStore(key) { ... } // TTL 缓存 function resolveCacheTtlMs() { ... } // 默认 TTL function createExpiringMapCache() { ... } // 过期 Map 缓存 2.7 Session Write Lock # 源码：session-write-lock.ts
// src/agents/session-write-lock.ts // 默认参数 const DEFAULT_STALE_MS = 1_800_000; // 30 分钟 const DEFAULT_MAX_HOLD_MS = 300_000; // 5 分钟 const DEFAULT_WATCHDOG_INTERVAL = 60_000; // 1 分钟 const DEFAULT_TIMEOUT_GRACE_MS = 120_000; // 2 分钟 // 获取 session 写锁 async function acquireSessionWriteLock(params) { const lockPath = `${sessionFile}.lock`; // 1. 可重入检查 const held = HELD_LOCKS.get(normalizedSessionFile); if (allowReentrant &amp;&amp; held) { held.count += 1; return { release: () =&gt; releaseHeldLock(...) }; } // 2. 重试循环 while (Date.now() - startedAt &lt; timeoutMs) { try { // wx 标志：文件存在则失败 const handle = await fs.open(lockPath, &#34;wx&#34;); await handle.writeFile(JSON.stringify({ pid: process.pid, createdAt: new Date().toISOString(), starttime: getProcessStartTime(process.pid) })); return { release }; } catch (err) { if (err.code !== &#34;EEXIST&#34;) throw err; // 检查 stale lock if (await shouldReclaimContendedLockFile(lockPath)) { await fs.rm(lockPath, { force: true }); continue; } // 指数退避 await sleep(delay); } } } // Watchdog 后台清理 function ensureWatchdogStarted(intervalMs) { setInterval(() =&gt; runLockWatchdogCheck(), intervalMs); } 3. 会话层：Session 生命周期 # 3.1 Session Key 路由 # 源码：session-key.ts / store.ts
// src/config/sessions/store.ts // Group Session Key 解析 function resolveGroupSessionKey(ctx) { const from = ctx.From; const chatType = ctx.ChatType; const provider = ctx.Provider; // 构建 key: provider:kind:id return { key: `${provider}:${kind}:${finalId}`, channel: provider, id: finalId, chatType: kind }; } // Group 显示名称构建 function buildGroupDisplayName(params) { const providerKey = params.provider ?? &#34;group&#34;; const detail = params.space || params.subject || &#34;&#34;; const token = normalizeGroupLabel(detail || fallbackId); return token ? `${providerKey}:${token}` : providerKey; } 3.2 Session 元数据合并 # 源码：types.ts
// src/config/sessions/types.ts // 合并 session 条目（保留活跃度信息） function mergeSessionEntryPreserveActivity(existing, next) { const merged = mergeSessionEntry(existing, next); // 保留活跃度相关字段 return merged; } 3.3 Session 交付上下文 # 源码：delivery-context.shared.ts
// Session 交付字段归一化 function normalizeSessionDeliveryFields(entry) { return { ...normalizeDeliveryContext(entry), ...normalizeSessionDeliveryFields(entry) }; } // 从 session 构建交付上下文 function deliveryContextFromSession(entry) { return { channel: entry.channel, accountId: entry.accountId, targetId: entry.targetId, // ... }; } 3.4 Session 元数据 # 源码：session-meta.ts
// Session 元数据管理 // - sessionStartedAt → daily reset 基准 // - lastInteractionAt → idle reset 基准 // - updatedAt → 列表/修剪用，不影响 freshness 3.5 Session 身份标识 # 源码：session-identity.ts / session-identifiers.ts
// Session 身份标识管理 // - 唯一 ID // - 关联 Agent // - 关联 Channel // - 关联 Conversation 4. 引擎层：Session Manager + Context Engine # 4.1 Session Manager 初始化 # OpenClaw 使用 @mariozechner/pi-coding-agent 库中的 SessionManager 作为核心会话管理器。
源码：session-manager-init.ts / session-manager-cache.ts
// SessionManager 初始化流程 // 1. 从 JSONL 文件加载 transcript // 2. 构建 SessionManager 实例 // 3. 缓存 SessionManager（减少重复加载） // 4. 预 warm session 文件 4.2 Session Manager 缓存 # 源码：session-manager-cache.ts
// Session Manager 缓存机制 // - 缓存 key: sessionKey // - 缓存 value: SessionManager 实例 // - 过期策略: TTL + 主动失效 // - 访问追踪: trackSessionManagerAccess() 4.3 Context Engine 生命周期钩子 # 源码：context-engine-maintenance.ts
// src/agents/pi-embedded-runner/context-engine-maintenance.ts // 安装 Context Engine 循环钩子 function installContextEngineLoopHook(params) { const { contextEngine, sessionId, sessionKey, sessionFile, tokenBudget, modelId } = params; return { async afterTurn(messages) { // 1. 调用 contextEngine.afterTurn() if (typeof contextEngine.afterTurn === &#34;function&#34;) { await contextEngine.afterTurn({ messages, sessionKey }); } // 2. Ingest 新消息到 Context Engine if (newMessages.length &gt; 0) { if (typeof contextEngine.ingestBatch === &#34;function&#34;) { await contextEngine.ingestBatch({ messages: newMessages }); } else { for (const message of newMessages) { await contextEngine.ingest({ message }); } } } // 3. Assemble 完整上下文 const assembled = await contextEngine.assemble({ tokenBudget, modelId }); return assembled; } }; } 核心流程：
每轮对话结束后： 1. afterTurn() → 通知 Context Engine 本轮完成 2. ingest() → 将新消息摄入 Context Engine 3. assemble() → 组装下一轮所需的上下文 4.4 Context Engine 维护（Maintenance） # 源码：context-engine-maintenance.ts
// src/agents/pi-embedded-runner/context-engine-maintenance.ts // 延迟维护任务常量 const TURN_MAINTENANCE_TASK_KIND = &#34;context_engine_turn_maintenance&#34;; const TURN_MAINTENANCE_TASK_LABEL = &#34;Context engine turn maintenance&#34;; const TURN_MAINTENANCE_WAIT_POLL_MS = 100; // 等待轮询间隔 const TURN_MAINTENANCE_LONG_WAIT_MS = 10000; // 长等待超时 // 执行上下文引擎维护 async function executeContextEngineMaintenance(params) { if (typeof params.contextEngine.maintain !== &#34;function&#34;) return; const result = await params.contextEngine.maintain({ sessionId: params.sessionId, sessionKey: params.sessionKey, sessionFile: params.sessionFile, runtimeContext: buildContextEngineMaintenanceRuntimeContext({ sessionManager: params.sessionManager, rewriteTranscriptEntries: async (request) =&gt; { // 重写 transcript 条目 return rewriteTranscriptEntriesInSessionManager({ sessionManager: params.sessionManager, replacements: request.replacements }); } }) }); if (result.changed) { log.info(`[context-engine] maintenance(${params.reason}) changed transcript`); } return result; } // 运行维护 async function runContextEngineMaintenance(params) { // 如果配置为后台模式，调度延迟任务 if (params.reason === &#34;turn&#34; &amp;&amp; params.contextEngine.info.turnMaintenanceMode === &#34;background&#34;) { scheduleDeferredTurnMaintenance(params); return; } // 否则同步执行 return executeContextEngineMaintenance(params); } 4.5 延迟维护调度 # // 延迟维护调度器 function scheduleDeferredTurnMaintenance(params) { const sessionKey = normalizeSessionKey(params.sessionKey); if (!sessionKey) return; // 检查是否已有活跃维护任务 const activeRun = activeDeferredTurnMaintenanceRuns.get(sessionKey); if (activeRun) { activeRun.rerunRequested = true; // 标记需要重新运行 return; } // 创建任务描述符 const task = buildTurnMaintenanceTaskDescriptor({ sessionKey }); // 入队到 session lane enqueueCommandInLane( resolveDeferredTurnMaintenanceLane(sessionKey), async () =&gt; runDeferredTurnMaintenanceWorker({ contextEngine: params.contextEngine, sessionId: params.sessionId, sessionKey, sessionFile: params.sessionFile, sessionManager: params.sessionManager, runId: task.runId }) ); } 4.6 延迟维护 Worker # // 延迟维护 Worker async function runDeferredTurnMaintenanceWorker(params) { const shutdownAbort = createDeferredTurnMaintenanceAbortSignal(); try { const sessionLane = resolveSessionLane(params.sessionKey); // 1. 等待 session lane 空闲 for (;;) { while (getQueueSize(sessionLane) &gt; 0) { await sleepWithAbort(TURN_MAINTENANCE_WAIT_POLL_MS, shutdownAbort.abortSignal); } await Promise.resolve(); if (getQueueSize(sessionLane) === 0) break; } // 2. 开始维护 startTaskRunByRunId({ runId: params.runId, progressSummary: &#34;Running deferred maintenance.&#34; }); const result = await executeContextEngineMaintenance({ contextEngine: params.contextEngine, executionMode: &#34;background&#34; }); // 3. 完成 completeTaskRunByRunId({ runId: params.runId, progressSummary: result?.changed ? &#34;Deferred maintenance completed with transcript changes.&#34; : &#34;Deferred maintenance completed.&#34; }); } catch (err) { // 错误处理 failTaskRunByRunId({ runId: params.runId, error: reason }); } finally { shutdownAbort.dispose(); } } 5. 维护层：Compaction + Transcript 管理 # 5.1 Transcript Rewrite # 源码：transcript-rewrite.ts
// Transcript 重写机制 // 在 SessionManager 中重写条目 async function rewriteTranscriptEntriesInSessionManager(params) { const { sessionManager, replacements } = params; // 根据 replacements 替换 transcript 中的条目 // 返回重写的条目数和释放的字节数 } // 在 Session 文件中重写条目 async function rewriteTranscriptEntriesInSessionFile(params) { const { sessionFile, sessionId, sessionKey, request } = params; // 直接操作 JSONL 文件 } 5.2 Tool Result 截断 # 源码：tool-result-truncation.ts
// src/agents/pi-embedded-runner/tool-result-truncation.ts // 动态计算 tool result 最大字符数 function resolveLiveToolResultMaxChars(params) { // 根据当前上下文窗口剩余空间动态调整 // 避免单个工具结果吃掉太多 token } // 截断 SessionManager 中过大的 tool results function truncateOversizedToolResultsInSessionManager(params) { const { sessionManager, contextWindowTokens } = params; const branch = sessionManager.getBranch(); const messages = branch.messages; // 估算每个消息的字符数 // 截断超过限制的 tool results // 重写 transcript const rewriteResult = rewriteTranscriptEntriesInSessionManager({ sessionManager, replacements }); } 5.3 字符估算 # 源码：session-file-repair.ts
// 字符估算常量 const IMAGE_CHAR_ESTIMATE = 8000; // 图片估算 8000 字符 // 估算消息字符数（带缓存） function estimateMessageCharsCached(msg, cache) { const hit = cache.get(msg); if (hit !== undefined) return hit; const estimated = estimateMessageChars(msg); cache.set(msg, estimated); return estimated; } // 不同类型消息的字符估算 function estimateMessageChars(msg) { if (msg.role === &#34;user&#34;) { // 用户消息：直接计算 return typeof content === &#34;string&#34; ? content.length : estimateContentBlockChars(content); } if (msg.role === &#34;assistant&#34;) { // 助手消息：text + thinking + toolCall let chars = 0; for (const block of content) { if (block.type === &#34;text&#34;) chars += block.text.length; else if (block.type === &#34;thinking&#34;) chars += block.thinking.length; else if (block.type === &#34;toolCall&#34;) chars += JSON.stringify(block.arguments ?? {}).length; } return chars; } if (isToolResultMessage(msg)) { // Tool result：加权计算（4/2 倍） const chars = estimateContentBlockChars(getToolResultContent(msg)); return Math.max(chars, Math.ceil(chars * 2)); } } // 上下文总字符估算（带缓存） function estimateContextChars(messages, cache) { return messages.reduce((sum, msg) =&gt; sum + estimateMessageCharsCached(msg, cache), 0); } 5.4 Compaction 常量 # 源码：pi-compaction-constants.ts
