// Compaction 后物理截断 transcript 文件 // 截断规则： // 1. 保留 session header // 2. 保留非 message 条目（custom, model_change, thinking_level_change, compaction 等） // 3. 截断旧消息，保留最近的消息 // 4. 确保 tool_use 和 tool_result 成对出现 6. 安全层：Repair + Guard # 6.1 Session 文件自修复 # 源码：session-file-repair.ts
// src/agents/session-file-repair.ts // Session 文件自修复 async function repairSessionFileIfNeeded(params) { const sessionFile = params.sessionFile.trim(); // 1. 读取文件 const content = await fs.readFile(sessionFile, &#34;utf-8&#34;); const lines = content.split(/\r?\n/); // 2. 逐行解析 JSON const entries = []; let droppedLines = 0; for (const line of lines) { if (!line.trim()) continue; try { const entry = JSON.parse(line); entries.push(entry); } catch { droppedLines += 1; // 记录丢弃行数 } } // 3. 验证 session header if (!isSessionHeader(entries[0])) { return { repaired: false, reason: &#34;invalid session header&#34; }; } // 4. 如果有损坏的行，执行修复 if (droppedLines &gt; 0) { const cleaned = entries.map(entry =&gt; JSON.stringify(entry)).join(&#34;\n&#34;); // 备份原文件 const backupPath = `${sessionFile}.bak-${process.pid}-${Date.now()}`; await fs.writeFile(backupPath, content); // 原子写入 const tmpPath = `${sessionFile}.repair-${process.pid}-${Date.now()}.tmp`; await fs.writeFile(tmpPath, cleaned); await fs.rename(tmpPath, sessionFile); return { repaired: true, droppedLines, backupPath }; } return { repaired: false, droppedLines: 0 }; } 6.2 Transcript Repair # 源码：session-transcript-repair.ts
// src/agents/session-transcript-repair.ts // 检测 thinking 块 function isThinkingLikeBlock(block) { return block?.type === &#34;thinking&#34; || block?.type === &#34;redacted_thinking&#34;; } // 检测原始工具调用块 function isRawToolCallBlock(block) { return typeof block?.type === &#34;string&#34; &amp;&amp; (block.type === &#34;toolCall&#34; || block.type === &#34;toolUse&#34; || block.type === &#34;functionCall&#34;); } // 检测工具调用 ID function hasToolCallId(block) { return typeof block?.id === &#34;string&#34; &amp;&amp; block.id.trim().length &gt; 0; } // 清理工具调用块 function sanitizeToolCallBlock(block) { const normalizedName = normalizeLowercaseStringOrEmpty(block.name?.trim()); // 特殊处理 sessions_spawn（红附件） if (normalizedName === &#34;sessions_spawn&#34;) { return { ...block, arguments: redactSessionsSpawnAttachmentsArgs(block.arguments), input: redactSessionsSpawnAttachmentsArgs(block.input) }; } return block; } // 检测 replay 安全的 thinking 助手回合 function isReplaySafeThinkingAssistantTurn(content, allowedToolNames) { let sawToolCall = false; // 检查是否包含不允许的工具调用 // 检查 tool_call 是否有对应的 tool_result return true; // 安全 } // 清理工具调用输入 function sanitizeToolCallInputs(block) { ... } // 创建缺失的 tool result function makeMissingToolResult(block) { ... } // 修复 tool use / result 配对 function repairToolUseResultPairing(messages) { ... } // 清理 tool use / result 配对 function sanitizeToolUseResultPairing(messages) { ... } 6.3 Tool Result Context Guard # 源码：tool-result-context-guard.ts
